/* ════ ui/form/select.js ════ */
// EF.ui.select — dropdown selector with custom-styled menu (no native <select>).
//
// opts: {
//   value: signal<any>, onChange?,
//   options: [{ value, label, icon? }],
//   placeholder?: string|signal,
//   disabled?: bool|signal,
//   variant?: 'default'|'minimal',
//   autoWidth?: bool,
// }
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  ui.select = function (opts) {
    const o = opts || {}
    const sig         = ui.asSig(o.value)
    const placeholder = ui.asSig(o.placeholder != null ? o.placeholder : 'Select...')
    const disabled    = ui.asSig(o.disabled    != null ? o.disabled    : false)
    const doWrite = ui.writer(sig, o.onChange, 'ui.select')
    const cls = 'ef-ui-select'
      + (o.variant === 'minimal' ? ' ef-ui-select-minimal' : '')
      + (o.autoWidth ? ' ef-ui-select-auto' : '')
    const el = ui.h('button', cls, { type: 'button' })
    const labelEl = ui.h('span', 'ef-ui-select-label')
    const arrow = ui.h('span', 'ef-ui-select-arrow', { text: '▾' })
    el.appendChild(labelEl); el.appendChild(arrow)
    ui.bindAttr(el, disabled, 'disabled')

    function findLabel(v) {
      const items = o.options || []
      for (let i = 0; i < items.length; i++) if (items[i].value === v) return items[i].label
      return null
    }
    function repaint() {
      const v = sig.peek()
      const lbl = findLabel(v)
      if (lbl != null) { labelEl.textContent = lbl; labelEl.classList.remove('ef-ui-select-placeholder') }
      else { labelEl.textContent = placeholder.peek() || 'Select...'; labelEl.classList.add('ef-ui-select-placeholder') }
    }
    ui.bind(el, sig,         repaint)
    ui.bind(el, placeholder, repaint)

    let pop = null
    el.addEventListener('click', function () {
      if (disabled.peek()) return
      if (pop) { pop.close(); pop = null; return }
      const list = ui.h('div', 'ef-ui-menu')
      const items = o.options || []
      for (let i = 0; i < items.length; i++) {
        const it = items[i]
        if (it.type === 'header') {
          list.appendChild(ui.h('div', 'ef-ui-menu-header', { text: it.label || '' }))
          continue
        }
        if (it.type === 'divider') {
          list.appendChild(ui.h('div', 'ef-ui-menu-divider'))
          continue
        }
        const row = ui.h('button', 'ef-ui-menu-item' + (it.value === sig.peek() ? ' ef-ui-menu-item-active' : ''), { type: 'button' })
        if (it.icon) row.appendChild(ui.icon({ glyph: it.icon }))
        const text = ui.h('span', 'ef-ui-menu-item-text')
        text.appendChild(ui.h('span', 'ef-ui-menu-item-label', { text: it.label != null ? it.label : String(it.value) }))
        if (it.subLabel) text.appendChild(ui.h('span', 'ef-ui-menu-item-sub', { text: it.subLabel }))
        row.appendChild(text)
        row.addEventListener('click', function () { doWrite(it.value); pop && pop.close(); pop = null })
        list.appendChild(row)
      }
      list.style.minWidth = Math.max(120, el.getBoundingClientRect().width) + 'px'
      list.style.maxHeight = Math.max(160, Math.min(420, window.innerHeight - 96)) + 'px'
      list.style.overflow = 'auto'
      pop = ui.popover({
        anchor: el,
        content: list,
        side: o.side || 'bottom',
        align: o.align || 'start',
        onDismiss: function () { pop = null },
      })
    })
    ui.collect(el, function () { if (pop) { pop.close(); pop = null } })

    return el
  }
})(window.EF = window.EF || {})

/* ════ ui/form/combobox.js ════ */
// EF.ui.combobox — text input + filtered dropdown.
//
// opts: {
//   value: signal<string>, onChange?,
//   options: string[] | [{value,label}],
//   placeholder?: string|signal,
//   disabled?: bool|signal,
// }
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  function norm(items) {
    return (items || []).map(function (it) {
      if (typeof it === 'string') return { value: it, label: it }
      return it
    })
  }

  ui.combobox = function (opts) {
    const o = opts || {}
    const sig         = ui.asSig(o.value       != null ? o.value       : '')
    const placeholder = ui.asSig(o.placeholder != null ? o.placeholder : '')
    const disabled    = ui.asSig(o.disabled    != null ? o.disabled    : false)
    const doWrite = ui.writer(sig, o.onChange, 'ui.combobox')
    const wrap = ui.h('div', 'ef-ui-field ef-ui-combobox')
    const inp = ui.h('input', 'ef-ui-input', { type: 'text' })
    const arrow = ui.h('span', 'ef-ui-field-suffix', { text: '▾' })
    wrap.appendChild(inp); wrap.appendChild(arrow)
    ui.bindAttr(inp, placeholder, 'placeholder')
    ui.bindAttr(inp, disabled, 'disabled')
    ui.bind(wrap, sig, function (v) { if (document.activeElement !== inp) inp.value = v == null ? '' : String(v) })

    let pop = null
    function open(showAll) {
      if (pop) return
      if (disabled.peek()) return
      const list = ui.h('div', 'ef-ui-menu')
      const term = showAll ? '' : inp.value.toLowerCase()
      const items = norm(ui.isSignal && ui.isSignal(o.options) ? o.options.peek() : o.options)
      const filtered = items.filter(function (it) { return !term || String(it.label).toLowerCase().indexOf(term) >= 0 })
      if (!filtered.length) {
        const empty = ui.h('div', 'ef-ui-menu-empty', { text: 'No matches' })
        list.appendChild(empty)
      }
      for (let i = 0; i < filtered.length; i++) {
        const it = filtered[i]
        const row = ui.h('button', 'ef-ui-menu-item', { type: 'button', text: it.label })
        row.addEventListener('mousedown', function (e) { e.preventDefault(); doWrite(it.value); inp.value = it.value; close() })
        list.appendChild(row)
      }
      list.style.minWidth = wrap.getBoundingClientRect().width + 'px'
      list.style.maxHeight = '240px'; list.style.overflow = 'auto'
      pop = ui.popover({ anchor: wrap, content: list, side: 'bottom', align: 'start', onDismiss: function () { pop = null } })
    }
    function close() { if (pop) { pop.close(); pop = null } }
    function reopen(showAll) { close(); open(showAll) }

    inp.addEventListener('focus', function () { open(true) })
    inp.addEventListener('input', function () { doWrite(inp.value); reopen(false) })
    arrow.addEventListener('mousedown', function (e) { e.preventDefault(); inp.focus(); pop ? close() : open(true) })
    ui.collect(wrap, close)

    return wrap
  }
})(window.EF = window.EF || {})

/* ════ ui/form/colorInput.js ════ */
// EF.ui.colorInput — color swatch + popover with HSV picker + hex input.
//
// opts:
//   value:     string|int|signal   hex ("#rrggbb") or 24-bit int (0xRRGGBB)
//   onChange?: (v) => void
//   valueKind?: 'hex' | 'int'      (default 'hex')   how the bound signal holds the value
//
// With valueKind='int', the signal stores an integer 0..0xFFFFFF. The swatch
// and picker internally work in hex strings; round-trip conversion happens at
// the signal boundary.
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  function toHexStr(v) {
    if (typeof v === 'number') {
      const n = Math.max(0, Math.min(0xffffff, Math.trunc(v || 0)))
      let s = n.toString(16); while (s.length < 6) s = '0' + s
      return '#' + s
    }
    return v
  }

  ui.colorInput = function (opts) {
    const o = opts || {}
    const valueKind = o.valueKind === 'int' ? 'int' : 'hex'
    const sig = ui.asSig(o.value != null ? o.value : (valueKind === 'int' ? 0x7b6ef6 : '#7b6ef6'))
    const rawWrite = ui.writer(sig, o.onChange, 'ui.colorInput')
    // Internal API operates on hex strings; translate to/from int at the edge.
    function doWrite(hex) {
      if (valueKind === 'int') rawWrite(parseInt(hex.slice(1), 16))
      else rawWrite(hex)
    }

    const el = ui.h('div', 'ef-ui-color')
    const swatch = ui.h('div', 'ef-ui-color-swatch')
    const text = ui.h('input', 'ef-ui-color-text', { type: 'text' })
    el.appendChild(swatch); el.appendChild(text)

    ui.bind(el, sig, function (v) {
      const hex = toHexStr(v)
      swatch.style.background = hex
      if (document.activeElement !== text) text.value = valueKind === 'int' ? String(v) : hex
    })
    text.addEventListener('input', function () {
      const raw = text.value.trim()
      // Accept "#rrggbb" / "#rgb" / a plain integer literal.
      if (/^#[0-9a-f]{6}$/i.test(raw) || /^#[0-9a-f]{3}$/i.test(raw)) {
        doWrite(raw)
      } else if (/^\d+$/.test(raw)) {
        const hex = toHexStr(parseInt(raw, 10))
        doWrite(hex)
      }
    })

    let pop = null
    swatch.addEventListener('click', function () {
      if (pop) { pop.close(); pop = null; return }
      pop = openPicker(el, sig, doWrite, function () { pop = null })
    })
    // If the component is disposed while the picker is open, tear it down.
    ui.collect(el, function () { if (pop) { pop.close(); pop = null } })
    return el
  }

  // ── HSV picker popover ─────────────────────────────────────────
  function openPicker(anchor, sig, doWrite, onClose) {
    const wrap = ui.h('div', 'ef-ui-color-picker')

    // The picker always works in hex internally; int-valued signals get
    // translated at the boundary by doWrite().
    const hsv = hexToHsv(toHexStr(sig.peek())) || { h: 0, s: 1, v: 1 }
    const sigH = EF.signal(hsv.h)
    const sigS = EF.signal(hsv.s)
    const sigV = EF.signal(hsv.v)

    // SV square
    const sv = ui.h('div', 'ef-ui-color-sv')
    const svDot = ui.h('div', 'ef-ui-color-sv-dot')
    sv.appendChild(svDot)
    // Hue strip
    const hue = ui.h('div', 'ef-ui-color-hue')
    const hueDot = ui.h('div', 'ef-ui-color-hue-dot')
    hue.appendChild(hueDot)
    // Hex input
    const hex = ui.h('input', 'ef-ui-color-hex', { type: 'text' })

    wrap.appendChild(sv); wrap.appendChild(hue); wrap.appendChild(hex)

    function update() {
      sv.style.background = 'linear-gradient(to top, #000, transparent), linear-gradient(to right, #fff, hsl(' +
                            (sigH.peek() * 360) + ',100%,50%))'
      svDot.style.left = (sigS.peek() * 100) + '%'
      svDot.style.top  = ((1 - sigV.peek()) * 100) + '%'
      hueDot.style.left = (sigH.peek() * 100) + '%'
      const out = hsvToHex(sigH.peek(), sigS.peek(), sigV.peek())
      doWrite(out)
      if (document.activeElement !== hex) hex.value = out
    }
    const stopEffect = EF.effect(function () { sigH(); sigS(); sigV(); update() })

    ui.attachDrag(sv, {
      onStart: scrubSv, onMove: scrubSv,
    })
    function scrubSv(e) {
      const r = sv.getBoundingClientRect()
      sigS.set(Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)))
      sigV.set(Math.max(0, Math.min(1, 1 - (e.clientY - r.top) / r.height)))
    }
    ui.attachDrag(hue, {
      onStart: scrubHue, onMove: scrubHue,
    })
    function scrubHue(e) {
      const r = hue.getBoundingClientRect()
      sigH.set(Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)))
    }
    hex.addEventListener('input', function () {
      const h = hexToHsv(hex.value.trim())
      if (h) { sigH.set(h.h); sigS.set(h.s); sigV.set(h.v) }
    })

    return ui.popover({
      anchor: anchor, content: wrap, side: 'bottom', align: 'start',
      onDismiss: function () { stopEffect(); onClose && onClose() },
    })
  }

  // ── color math ─────────────────────────────────────────────────
  function hexToHsv(hex) {
    if (!hex) return null
    let m = /^#?([0-9a-f]{3}|[0-9a-f]{6})$/i.exec(hex)
    if (!m) return null
    let h = m[1]
    if (h.length === 3) h = h[0]+h[0]+h[1]+h[1]+h[2]+h[2]
    const r = parseInt(h.slice(0,2), 16) / 255
    const g = parseInt(h.slice(2,4), 16) / 255
    const b = parseInt(h.slice(4,6), 16) / 255
    const mx = Math.max(r,g,b), mn = Math.min(r,g,b), d = mx - mn
    let H = 0
    if (d > 0) {
      if (mx === r) H = ((g - b) / d) % 6
      else if (mx === g) H = (b - r) / d + 2
      else H = (r - g) / d + 4
      H = (H * 60 + 360) % 360 / 360
    }
    const S = mx === 0 ? 0 : d / mx
    const V = mx
    return { h: H, s: S, v: V }
  }
  function hsvToHex(h, s, v) {
    const i = Math.floor(h * 6)
    const f = h * 6 - i
    const p = v * (1 - s)
    const q = v * (1 - f * s)
    const t = v * (1 - (1 - f) * s)
    let r, g, b
    switch (i % 6) {
      case 0: r = v; g = t; b = p; break
      case 1: r = q; g = v; b = p; break
      case 2: r = p; g = v; b = t; break
      case 3: r = p; g = q; b = v; break
      case 4: r = t; g = p; b = v; break
      case 5: r = v; g = p; b = q; break
    }
    function h2(x) { return ('0' + Math.round(x * 255).toString(16)).slice(-2) }
    return '#' + h2(r) + h2(g) + h2(b)
  }
})(window.EF = window.EF || {})

/* ════ ui/form/dateInput.js ════ */
// EF.ui.dateInput — date entry via the browser's native date picker.
//
