//     { cls: 'p', re: /[(){};]/y },
//     { cls: 't', re: /\s+/y },
//     { cls: 't', re: /./y },
//   ]
//   ui.codeInput({
//     value: sig, language: 'js',
//     highlight: src => ui.codeInput.tokenize(src, jsRules),
//   })
