/* ════ ui/panel/dock-tabs.js ════ */
// Dock-tabs — the framework-side thin shell around EF.ui.tab.
//
// Zero visual code. Zero DOM construction. Its entire job is:
//   1. Pick an EF.ui.tab variant from preset defaults
//   2. Wire ctx.dock.panels → items, ctx.dock.activeId → active
//   3. Forward click / close / add / drag callbacks to ctx.dock.*
//   4. Tag the root with `.ef-dock-tabs` so interactions.js can hit-test it
//
// Registered presets (§ 4.6 — one implementation, four configurations):
//   tab-standard    closeable + addable                    (editor)
//   tab-compact     no close, hides when < 2 panels        (properties)
//   tab-collapsible closeable + click-active collapses     (utility)
//   tab-sidebar     icon-only + collapsible                (rail style)
//
// A preset's `props` can override any of the hard-coded defaults on a
// per-toolbar-item basis — that's how a caller could, e.g., use the
// sidebar preset but force text mode with `props: { iconOnly: false }`,
// or force a direction with `props: { direction: 'vertical' }`.
;(function (EF) {
  'use strict'

  function buildDockTabs(p, ctx) {
    const dockDir = ctx.dock.toolbarDirection ? ctx.dock.toolbarDirection.peek() : null
    const autoDir = (dockDir === 'left' || dockDir === 'right') ? 'vertical' : 'horizontal'
    const el = EF.ui.tab({
      items:        ctx.dock.panels,     // derived signal<PanelData[]>
      active:       ctx.dock.activeId,   // derived signal<string|null>
      variant:      p.variant  || 'bar',
      direction:    p.direction || autoDir,
      iconOnly:     p.iconOnly,
      closable:     p.closable != null ? p.closable : true,
      addable:      !!p.addable,
      minShowCount: p.minShowCount || 0,

      onActivate: function (id) {
        ctx.dock.activatePanel(id)
        if (p.collapsible && ctx.dock.canCollapse()) ctx.dock.setCollapsed(false)
      },
      onReactivate: function () {
        if (p.collapsible && ctx.dock.canCollapse()) {
          ctx.dock.setCollapsed(!ctx.dock.collapsed())
        }
      },
      onClose: function (id) {
        ctx.dock.removePanel(id)
      },
      onAdd: function () {
        const panels = ctx.dock.panels()
        const curId  = ctx.dock.activeId()
        const active = panels.find(function (pp) { return pp.id === curId })
        if (!active) return
        const defaults = EF.componentDefaults(active.component)
        ctx.dock.addPanel(Object.assign({}, defaults, { component: active.component }))
      },
      onDragStart: function (ev, panelId) {
        const fn = EF._dock && EF._dock.beginPanelDrag
        if (fn) fn(ev, panelId, ctx.dock.id(), ctx._layout)
      },
    })
    el.classList.add('ef-dock-tabs')
    return el
  }

  // Preset-bound factory — props are static for the lifetime of the toolbar
  // item, so .peek() once at construction is sufficient.
  function preset(defaults) {
    return function (propsSig, ctx) {
      return buildDockTabs(Object.assign({}, defaults, propsSig.peek() || {}), ctx)
    }
  }

  EF.registerComponent('tab-standard', {
    defaults: function () { return { title: 'Tabs' } },
    factory:  preset({ variant: 'bar', closable: true, addable: true }),
  })

  EF.registerComponent('tab-compact', {
    defaults: function () { return { title: 'Tabs' } },
    factory:  preset({ variant: 'compact', closable: false, minShowCount: 2 }),
  })

  EF.registerComponent('tab-collapsible', {
    defaults: function () { return { title: 'Tabs' } },
    factory:  preset({ variant: 'bar', closable: true, collapsible: true }),
  })

  EF.registerComponent('tab-sidebar', {
    defaults: function () { return { title: 'Tabs' } },
    factory:  preset({
      variant:     'sidebar',
      iconOnly:    true,
      closable:    false,
      collapsible: true,
    }),
  })
})(window.EF = window.EF || {})

/* ════ ui/panel/log.js ════ */
// Log panel component — built entirely from EF.ui.* primitives.
//
// Subscribes to EF.log and renders one ef-ui-card per entry inside a
// ef-ui-scrollarea. Newest on top. A segmented
// level filter (All / Error / Warn / Info / Debug) controls the visible
// subset. This is a built-in `registered panel component` (§ 4.7) — users put
// it in any dock and they immediately see every panel error / log call /
// global throw / async rejection routed to one place.
//
// Zero custom DOM, zero custom CSS. Everything comes from the ui library.
;(function (EF) {
  'use strict'
  const ui = EF.ui

  const LEVEL_OPTS = [
    { value: 'all',   label: 'All' },
    { value: 'error', label: 'Error' },
    { value: 'warn',  label: 'Warn' },
    { value: 'info',  label: 'Info' },
    { value: 'debug', label: 'Debug' },
  ]

  function factory(propsSig, ctx) {
    const root = ui.h('div', 'ef-ui-errlog')

    // Filter bar — dropdown select on the left, spacer, copy + clear on the
    // right. Select (not segmented) keeps the toolbar compact when the log
    // panel is narrow.
    const filter = EF.signal(((propsSig.peek() || {}).level) || 'all')
    const bar = ui.h('div', 'ef-ui-errlog-bar')
    bar.appendChild(ui.select({ value: filter, options: LEVEL_OPTS }))
    const summary = ui.h('div', 'ef-ui-errlog-summary')
    bar.appendChild(summary)
    bar.appendChild(ui.h('div', 'ef-ui-errlog-spacer'))
    const copyBtn = ui.button({ text: 'Copy', kind: 'ghost', size: 'sm' })
    copyBtn.addEventListener('click', function () {
      const list = EF.log()
      const lvl = filter()
      const visible = lvl === 'all' ? list : list.filter(function (e) { return e.level === lvl })
      const text = visible.map(function (e) {
        return '[' + e.level.toUpperCase() + '] ' + formatSource(e.source) + ' — ' + e.message +
          (e.stack ? '\n' + e.stack : '')
      }).join('\n')
      ui.copyText(text).then(function () {
        ui.toast({ kind: 'success', message: 'Copied ' + visible.length + ' log entries' })
      })
    })
    bar.appendChild(copyBtn)
    const clearBtn = ui.button({ text: 'Clear', kind: 'ghost', size: 'sm' })
    clearBtn.addEventListener('click', function () { EF.log.clear() })
    bar.appendChild(clearBtn)
    root.appendChild(bar)

    const empty = ui.h('div', 'ef-ui-errlog-empty', {
      text: 'No log entries',
    })

    const scroll = ui.scrollArea()
    root.appendChild(scroll)

    ctx.onCleanup(EF.effect(function () {
      const list = EF.log()
      const lvl = filter()
      const visible = lvl === 'all' ? list : list.filter(function (e) { return e.level === lvl })
      summary.textContent = visible.length + ' visible / ' + list.length + ' total'
      scroll.replaceChildren()
      if (visible.length === 0) {
        scroll.appendChild(empty)
        return
      }
      // Newest first.
      for (let i = visible.length - 1; i >= 0; i--) {
        scroll.appendChild(buildRow(visible[i]))
      }
    }))

    return root
  }

  function buildRow(entry) {
    const row = ui.h('div', 'ef-ui-errlog-row ef-ui-errlog-row-' + entry.level)
    row.appendChild(ui.h('div', 'ef-ui-errlog-msg',  { text: entry.message }))
    // Stack trace lives in the entry data (and console.error fallback) but is
    // not rendered. Level/source/time are represented by filtering, copy, and
    // the color strip; the visible list stays message-first.
    row.title = entry.stack ? entry.message + '\n\n' + entry.stack : entry.message
    return row
  }

  function formatSource(s) {
    if (!s) return 'unknown'
    const parts = [s.scope || 'unknown']
    if (s.component)  parts.push('component=' + s.component)
    if (s.dockId)  parts.push('dock=' + s.dockId)
    if (s.panelId) parts.push('panel=' + s.panelId)
    if (s.topic)   parts.push('topic=' + s.topic)
    return parts.join(' · ')
  }

  EF.registerComponent('log', {
    label:    'Log',
    icon:     'list',
    category: 'panel',
    defaults: function () { return { title: 'Log', icon: '📋', props: { level: 'all' } } },
    factory:  factory,
  })
})(window.EF = window.EF || {})

